#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int Min(int x,int y){return x<y?x:y;}
inline int Max(int x,int y){return x>y?x:y;}
const int N=15,SS=(1<<12)|7,INF=1e15;
int dis[N][N],trs[SS],dp[SS][N];
signed main()
{
	int n=read(),m=read();rep(1,n,i)rep(1,n,j)dis[i][j]=INF;
	rep(1,m,i){int x=read(),y=read();dis[x][y]=dis[y][x]=Min(dis[x][y],read());}
	int len=(1<<n)-1;rep(1,len,i)
	{
		rep(0,n-1,j)if(i&(1<<j))
		{
			dis[j+1][j+1]=0;
			rep(0,n-1,k)if(dis[j+1][k+1]!=INF)trs[i]|=(1<<k);
		}
	}
//	rep(0,len,i)printf("%d ",trs[i]);puts("");
	rep(0,len,i)rep(0,n-1,j)dp[i][j]=INF;rep(0,n-1,i)dp[1<<i][0]=0;
	rep(2,len,i)for(int S=i&(i-1);S;S=(S-1)&i)if((trs[S]&i)==i)
	{
		int sum=0,cpl=S^i;//printf("%d -> %d\n",i,S);
		rep(0,n-1,j)if((1<<j)&cpl){int mn=INF;rep(0,n-1,k)if((1<<k)&S)mn=Min(mn,dis[j+1][k+1]);sum+=mn;}
		rep(1,n-1,j)if(dp[S][j-1]!=INF)dp[i][j]=Min(dp[i][j],dp[S][j-1]+sum*j);
	}
//	rep(1,len,i){rep(0,n-1,j)printf("%lld ",dp[i][j]);puts("");}
	long long ans=INF;rep(0,n-1,i)ans=Min(ans,dp[len][i]);printf("%lld\n",ans);return 0;
}
